## 3. Server‑Side Token Validation (Node.js / Express Example)

> **Offensive note:** If an attacker can bypass the front‑end and call your API directly, the only line of defense is **server‑side JWT verification**.  

```js
// server.js (Express)
const express = require('express');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');
const cookieParser = require('cookie-parser');

const app = express();
app.use(express.json());
app.use(cookieParser());

// 1️⃣ JWKS client – fetches Azure AD signing keys (cached)
const jwks = jwksClient({
  jwksUri: `https://login.microsoftonline.com/<YOUR_TENANT_ID>/discovery/v2.0/keys`,
  cache: true,
  rateLimit: true
});

// Helper to retrieve signing key
function getKey(header, callback) {
  jwks.getSigningKey(header.kid, (err, key) => {
    if (err) return callback(err);
    const signingKey = key.getPublicKey();
    callback(null, signingKey);
  });
}

// 2️⃣ Middleware – validates the httpOnly session cookie
function validateJwt(req, res, next) {
  const token = req.cookies.sessionJwt; // set by /api/session endpoint
  if (!token) return res.status(401).json({ error: 'Missing token' });

  jwt.verify(token, getKey, {
    algorithms: ['RS256'],
    audience: '<YOUR_CLIENT_ID>',
    issuer: `https://login.microsoftonline.com/<YOUR_TENANT_ID>/v2.0`
  }, (err, payload) => {
    if (err) {
      console.warn('JWT validation failed:', err);
      return res.status(401).json({ error: 'Invalid token' });
    }
    // Attach claims for downstream RBAC checks
    req.user = payload;
    next();
  });
}

// 3️⃣ Session creation endpoint (called from the SPA)
app.post('/api/session', async (req, res) => {
  const { idToken, accessToken } = req.body;
  // Verify both tokens (you may only need the ID token for auth)
  // Re‑use the same verification logic as above.
  // If verification passes, set an httpOnly cookie:
  res.cookie('sessionJwt', idToken, {
    httpOnly: true,
    secure: true,          // only over HTTPS
    sameSite: 'strict',
    maxAge: 15 * 60 * 1000 // 15 min (adjust as needed)
  });
  res.sendStatus(200);
});

// 4️⃣ Protected API example
app.get('/api/reports', validateJwt, (req, res) => {
  // Server‑side RBAC – only Admin or Analyst may read reports
  const roles = req.user.roles || [];
  if (!roles.includes('Admin') && !roles.includes('Analyst')) {
    return res.status(403).json({ error: 'Forbidden' });
  }
  // Return real data from DB …
  res.json({ report: 'Confidential financial data' });
});

// 5️⃣ Session revocation (logout)
app.delete('/api/session', (req, res) => {
  res.clearCookie('sessionJwt', { httpOnly: true, secure: true, sameSite: 'strict' });
  res.sendStatus(200);
});

app.listen(443, () => console.log('Secure Entra‑ID API listening on 443'));
```

**Why this matters**

| OWASP / CWE | Mitigated Issue |
|-------------|-----------------|
| A01 – Broken Access Control (CWE‑284/285) | Server‑side RBAC ensures the client cannot simply “show” a hidden UI element to gain data. |
| A03 – Injection (XSS) (CWE‑79) | Tokens are never exposed to JavaScript, so a successful XSS cannot steal them. |
| A06 – Cryptographic Failures (CWE‑295) | JWKS‑based signature verification guarantees token integrity. |
| A07 – Identification & Authentication Failures (CWE‑287) | Logout endpoint clears the httpOnly cookie and forces IdP sign‑out. |
| A05 – Security Misconfiguration (CWE‑16) | `secure`, `httpOnly`, `sameSite=Strict` cookie flags enforce transport security. |

